            }
        }
        let count = fields.len();
        metadata.insert("fields".to_string(), format!("[{}]", fields.join(",")));
        metadata.insert("field_count".to_string(), count.to_string());
    }

    Some(build_node_data(
        &name,
        NodeKind::Struct,
        node,
        source,
        file_path,
